class MinStack {
private:
    stack<int> stack;
    stack<int> minStack;

public:
    MinStack() {

    }

    void push(int val) {
        stack.push(val);
        if (minStack.empty() || val <= minStack.top()) {
            minStack.push(val);
        }
    }

    void pop() {
        if (!stack.empty()) {
            if (stack.top() == minStack.top()) {
                minStack.pop();
            }
            stack.pop();
        }
    }

    int top() {
        if (!stack.empty()) {
            return stack.top();
        }
        return -1; // Return -1 if the stack is empty
    }

    int getMin() {
        if (!minStack.empty()) {
            return minStack.top();
        }
        return -1; // Return -1 if the stack is empty
    }
};
```

